from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n):
    if n < 2: return n
    return fib(n - 1) + fib(n - 2)

print(fib(60))   # instant; without lru_cache it would take ~10^12 calls

def build_prefix(arr):
    pre = [0] * (len(arr) + 1)
    for i, x in enumerate(arr):
        pre[i + 1] = pre[i] + x
    return pre

def range_sum(pre, l, r):
    return pre[r] - pre[l]

pre = build_prefix(list(range(1_000_000)))
print(range_sum(pre, 100, 200))

def sum_file_in_memory(path):
    return sum(int(x) for x in open(path).read().split())   # O(n) memory

def sum_file_streamed(path):
    total = 0
    with open(path) as f:
        for line in f:
            total += int(line)                                # O(1) memory
    return total

def edit_distance_rolling(a, b):
    m, n = len(a), len(b)
    prev = list(range(n + 1))
    for i in range(1, m + 1):
        curr = [i] + [0] * n
        for j in range(1, n + 1):
            if a[i - 1] == b[j - 1]:
                curr[j] = prev[j - 1]
            else:
                curr[j] = 1 + min(prev[j], curr[j - 1], prev[j - 1])
        prev = curr
    return prev[n]

import time
from functools import lru_cache
from dataclasses import dataclass

@dataclass
class Stamped:
    value: object
    ts: float

cache: dict[str, Stamped] = {}

def get_with_ttl(key, fetch, ttl=60.0):
    now = time.time()
    hit = cache.get(key)
    if hit and now - hit.ts < ttl:
        return hit.value           # cheap hit
    value = fetch(key)             # expensive call
    cache[key] = Stamped(value, now)
    return value
